package ai.singlr.sail.gen;

import ai.singlr.sail.config.SailYaml;
import ai.singlr.sail.engine.AgentCli;
import java.util.List;

/**
 * Generates the cross-agent security audit bash script. When a secondary agent is configured as
 * auditor, generates a bash script that invokes the auditor to review code diffs for security
 * vulnerabilities.
 *
 * <p>Pure utility — no I/O, no shell execution. Callers push the generated files into the
 * container. Hooks configuration is handled by {@link PostTaskHooksGenerator}.
 */
public final class SecurityAuditGenerator {

  private SecurityAuditGenerator() {}

  /**
   * Generates the audit script for cross-agent security review. Returns an empty list if security
   * audit is not enabled or no auditor is available.
   */
  public static List<GeneratedFile> generateFiles(SailYaml config) {
    if (config.agent() == null
        || config.agent().securityAudit() == null
        || !config.agent().securityAudit().enabled()) {
      return List.of();
    }

    var audit = config.agent().securityAudit();
    var auditorName = audit.resolveAuditor(config.agent().type(), config.agent().install());
    if (auditorName == null) {
      return List.of();
    }
    var auditorBinary = AgentCli.fromYamlName(auditorName).binaryName();
    var sshUser = config.sshUser();
    var scriptPath = "/home/" + sshUser + "/.sail/security-audit.sh";

    var scriptContent = generateAuditScript(auditorBinary);
    return List.of(new GeneratedFile(scriptPath, scriptContent, true));
  }

  /** Generates the bash audit script that invokes the auditor agent on the code diff. */
  static String generateAuditScript(String auditorBinary) {
    return """
        #!/usr/bin/env bash
        set -euo pipefail

        # Cross-agent security audit — invokes %s to review code changes.
        # Generated by `sail project create`. Do not edit.

        DIFF=$(git diff main..HEAD -- . ':!*.lock' ':!*.min.js' ':!*.min.css' 2>/dev/null || true)
        if [ -z "$DIFF" ]; then
          exit 0
        fi

        AUDIT_PROMPT="You are a security auditor reviewing a code diff. Analyze it for:
        1. OWASP Top 10 vulnerabilities (injection, XSS, broken auth, SSRF, IDOR, etc.)
        2. Hardcoded secrets, API keys, tokens, passwords, or credentials
        3. Missing input validation at system boundaries (user input, external APIs, file uploads)
        4. Unsafe deserialization, path traversal, or command injection
        5. Insecure cryptographic practices (weak algorithms, hardcoded IVs, etc.)
        6. SQL injection, NoSQL injection, or ORM misuse
        7. Broken access control or privilege escalation paths
        8. Server-side request forgery (SSRF) or open redirects

        For each issue found, report:
        - File and line number
        - Severity (critical/high/medium/low)
        - Description of the vulnerability
        - Recommended remediation

        If the code is clean and no security issues are found, respond with exactly: PASS

        --- BEGIN DIFF ---
        ${DIFF}
        --- END DIFF ---"

        RESULT=$(%s --print "$AUDIT_PROMPT" 2>/dev/null || echo "AUDIT_ERROR")

        if echo "$RESULT" | grep -q "^PASS"; then
          exit 0
        else
          echo "$RESULT" > ~/security-audit.md
          echo "Security audit found issues. See ~/security-audit.md" >&2
          exit 2
        fi
        """
        .formatted(auditorBinary, auditorBinary);
  }
}
